export function hasGen2Sprite(slug) {
  return AVAILABLE.has(slug);
}

export function hasGen2Gif(slug) {
  return HAS_GIF.has(slug);
}

export function getGen2Png(slug, { shiny = false } = {}) {
  if (!AVAILABLE.has(slug)) return null;
  return BASE + slug + (shiny ? '.shiny' : '') + '.png';
}

// animated entrance (gen 2 / crystal demake style). null when no gif was
// shipped for this slug (static-only candidates) so consumers don't
// request a url that 404s.
export function getGen2Gif(slug, { shiny = false } = {}) {
  if (!HAS_GIF.has(slug)) return null;
  return BASE + slug + (shiny ? '.shiny' : '') + '.gif';
}

export function getGen2Sprites({ form, species, shiny = false }) {
  const primary = (form && AVAILABLE.has(form)) ? form : species;
  if (!AVAILABLE.has(primary)) return null;
  return {
    png: getGen2Png(primary, { shiny }),
    gif: getGen2Gif(primary, { shiny }),
  };
}

// returns { artist, source, sourceUrl, creditUrl } | null. follows the same
// form→species fallback logic as getGen2Sprites so a form's card credits
// the species-level artist when the form itself isn't curated.
export function getGen2Credit(slug) {
  if (CREDITS[slug]) return CREDITS[slug];
  return null;
}
